    // ------------------------------------------------------------------------------------------------------------
    // Poprawiona funkcja dodająca przyciski kopiowania numerów rejestracyjnych
    function addLicensePlateCopyButtons() {
      $(
        "span[ng-if='yardAsset.vehicleNumber'], span[ng-if='yardAsset.licensePlateIdentifier && yardAsset.licensePlateIdentifier.registrationIdentifier']",
      ).each(function () {
        var numberHtml = $(this).html() || "";
        var number = numberHtml.split("<br>")[0].trim();

        if ($(this).parent().parent().find("button.oxy-copy-btn").length < 1) {
          var copyButton = $("<button>", {
            class: "oxy-copy-btn superuserTooltip",
            title: "COPY TO CLIPBOARD",
            text: "COPY",
          }).click(function (e) {
            e.preventDefault();
            navigator.clipboard
              .writeText(number.split(" ")[0])
              .then(() => {
                let ref = $(this);
                ref.text("COPIED!");

                setTimeout(function () {
                  ref.text("COPY");
                }, 2000);
              })
              .catch((err) => {
                console.error("Błąd kopiowania:", err);
              });
          });

          $(this).parent().parent().append($("<br>")).append(copyButton);
        }
      });
    }

    // Funkcja sprawdzająca i dodająca przyciski
    function checkAndAddButtons() {
      if ($("#noteTextArea").is(":visible")) {
        if (
          $("#sealStatusDiv").length === 0 &&
          typeof addSealStatusButtons === "function"
        ) {
          addSealStatusButtons();
        }
        if (
          $("#pageToggleButton").length === 0 &&
          typeof createToggleButton === "function"
        ) {
          createToggleButton();
        }

        $("#pageToggleButton").show();

        if ($("#pageToggleButton").text() === "Next Page") {
          $("#sealStatusDiv").show();
          if ($("#page2Content").length > 0) {
            $("#page2Content").hide();
          }
        } else {
          $("#sealStatusDiv").hide();
          if (
            $("#page2Content").length === 0 &&
            typeof createPage2 === "function"
          ) {
            createPage2();
          }
          $("#page2Content").show();
        }
      } else {
        $("#sealStatusDiv, #page2Content, #pageToggleButton").hide();
      }
      addLicensePlateCopyButtons();

      // Detekcja i kolorowanie ładunków WRO5 -> BCN4
      $("span[title='WRO5->BCN4']").each(function () {
        if (!$(this).hasClass("wro-bcn-colored")) {
          $(this).addClass("wro-bcn-colored");

          // Stylizacja samego identyfikatora
          $(this).css({
            "background-color": "#ffeb3b", // Jasnożółty
            "color": "#d50000",          // Czerwony tekst
            "font-weight": "bold",
            "padding": "2px 5px",
            "border-radius": "3px",
            "border": "1px solid #d50000"
          });

          // Podświetlenie tła/obramowania dla całego wiersza naczepy
          $(this).closest("tr.ng-scope").css({
             "box-shadow": "inset 0 0 0 2px #ffeb3b",
             "background-color": "rgba(255, 235, 59, 0.05)"
          });
        }
      });
    }

    // Zapewnienie, że przyciski pojawią się w dynamicznie ładowanej aplikacji (Angular)
    setInterval(function () {
      checkAndAddButtons();
    }, 1500);

    // ------------------------------------------------------------------------------------------
    // Variable to track the visibility of the div with id "top-section"
    var isTopSectionVisible = true;
    var toggleButton;

    // Function to toggle changes on various elements
    function toggleChanges() {
      var topbarData = document.getElementById("topbarData");
      var searchResults = document.querySelector(".ship-clerk-search-results");
      var tcpWidget = document.querySelector(".tcp-widget");
      var scrollTable = document.querySelector(".scrolltable");
      var topSection = document.getElementById("top-section");

      if (
        topbarData &&
        searchResults &&
        tcpWidget &&
        scrollTable &&
        topSection
      ) {
        // Toggle the changes for topbarData
        if (topbarData.style.visibility === "hidden") {
          topbarData.style.visibility = "visible";
          topbarData.style.opacity = "1";
          topbarData.style.zIndex = "1";
          toggleButton.innerHTML = "Collapse";
        } else {
          topbarData.style.visibility = "hidden";
          topbarData.style.opacity = "0";
          topbarData.style.zIndex = "-999";
          toggleButton.innerHTML = "Grow";
        }

        // Toggle the changes for searchResults
        if (searchResults.style.marginTop === "-179px") {
          searchResults.style.marginTop = "0";
          searchResults.style.zIndex = "auto";
        } else {
          searchResults.style.marginTop = "-179px";
          searchResults.style.zIndex = "999";
        }

        // Toggle the changes for tcpWidget
        if (tcpWidget.style.visibility === "collapse") {
          tcpWidget.style.visibility = "visible";
        } else {
          tcpWidget.style.visibility = "collapse";
        }

        // Toggle the changes for scrollTable
        if (scrollTable.style.height === "150%") {
          scrollTable.style.height = "100%";
        } else {
          scrollTable.style.height = "150%";
        }

        // Toggle the visibility of topSection
        if (isTopSectionVisible) {
          topSection.style.display = "none";
          isTopSectionVisible = false;
        } else {
          topSection.style.display = "-webkit-flex";
          isTopSectionVisible = true;
        }
      }
    }

    // Function to add the button after a 5-second delay
    // We must add the 5-second delay to account for the internal page refresh after the browser is done loading.
    function addToggleButton() {
      // Find the div with id "clearButtonGroup"
      var clearButtonGroup = document.getElementById("clearButtonGroup");
      // Check if the div is found
      if (clearButtonGroup) {
        // Set "clearButtonGroup" as a flex container with justifyContent center to allow appeneded button to align horizontal
        clearButtonGroup.style.display = "flex";
        clearButtonGroup.style.justifyContent = "center";
        clearButtonGroup.style.alignItems = "center"; // Optionally align items at the center

        // Create a new button element
        toggleButton = document.createElement("button");
        toggleButton.innerHTML = "Collapse";
        toggleButton.style.cursor = "pointer";

        // Add click event to toggle changes on various elements
        toggleButton.addEventListener("click", toggleChanges);

        // Append the button to the "clearButtonGroup" div
        clearButtonGroup.appendChild(toggleButton);
      }
    }

    // Wait for a 5-second delay after the page is fully loaded
    setTimeout(addToggleButton, 5000);
  }
})(window, document);


